prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?init WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" .
  ?model tai:belongsTo ?org .
  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  # Identify initial node(s): start event(s)
  ?init a bboExt:StartEvent ;
        tai:belongsTo ?choreo .
  ?init bbo:name ?initName .

  # Tasks
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER NOT EXISTS {
    ?init ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?missingFrom WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  # tasks
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  # initial nodes: any node of type StartEvent (name may be missing)
  ?init a bboExt:StartEvent ;
        tai:belongsTo ?choreo .
  BIND(COALESCE(STR(?init), "<no-start-uri>") AS ?missingFrom)

  FILTER NOT EXISTS {
    ?init ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?task) AS ?totalTasks)
       (COUNT(DISTINCT ?reachableTask) AS ?reachableTasks)
       (COUNT(DISTINCT ?init) AS ?startEvents)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL {
    ?init a bboExt:StartEvent ;
          tai:belongsTo ?choreo .
    ?init ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachableTask .
    ?reachableTask a bboExt:ChoreographyTask ;
                    tai:belongsTo ?choreo .
  }
}
GROUP BY ?model

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?norm ?orig ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?norm . }
  OPTIONAL { ?model tai:originalId ?orig . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER( (BOUND(?norm) && CONTAINS(LCASE(STR(?norm)), "1ad939eef40c461dafae27f75a0586d3"))
       || (BOUND(?orig) && CONTAINS(LCASE(STR(?orig)), "1ad939eef40c461dafae27f75a0586d3")) )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?initName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  ?init a bboExt:StartEvent ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?init bbo:name ?initName . }

  FILTER NOT EXISTS {
    ?init ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName (MIN(?isUnreachable) AS ?unreachableFlag) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  # compute unreachable from any start event in the same choreography
  OPTIONAL {
    ?init a bboExt:StartEvent ;
          tai:belongsTo ?choreo .
    FILTER NOT EXISTS {
      ?init ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    }
  }

  BIND(
    IF(EXISTS {
      ?model a bboExt:Model ; tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
      ?defs tai:belongsTo ?model .
      ?choreo tai:belongsTo ?defs .
      ?init a bboExt:StartEvent ; tai:belongsTo ?choreo .
      FILTER NOT EXISTS { ?init ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task . }
    }, 1, 0) AS ?isUnreachable
  )
}
GROUP BY ?task ?taskName
ORDER BY ?unreachableFlag ?taskName
LIMIT 25
